import crypto from 'node:crypto';

function checkAppleCredentials(decryptedKey: { username: string; password: string }, username: string, password: string): boolean {
  const usernameBuffer = Buffer.from(decryptedKey.username);
  const providedUsernameBuffer = Buffer.from(username);

  const passwordBuffer = Buffer.from(decryptedKey.password);
  const providedPasswordBuffer = Buffer.from(password);

  let usernameMatch = false;
  let passwordMatch = false;

  // Compare usernames with timing-safe comparison if lengths match
  if (usernameBuffer.length === providedUsernameBuffer.length) {
    usernameMatch = crypto.timingSafeEqual(usernameBuffer, providedUsernameBuffer);
  }

  // Compare passwords with timing-safe comparison if lengths match
  if (passwordBuffer.length === providedPasswordBuffer.length) {
    passwordMatch = crypto.timingSafeEqual(passwordBuffer, providedPasswordBuffer);
  }

  return usernameMatch && passwordMatch;
}
